import { G as GlobalThemeContext, F as FontsResult } from './types-ssjav-St.js';
import { StyleObject, ThemeMode } from '@global-theme/core';

/**
 * Generates the global theme context initialization script for server-side rendering.
 * This script should be embedded in the HTML to hydrate the client-side context.
 *
 * @returns Script object with id and serialized theme context, or undefined if context is not initialized
 */
declare function getGlobalThemeContextScript(): Promise<{
    id: string;
    children: string;
} | undefined>;

/**
 * Runs the callback within a global theme context.
 * The store will be available to all async operations initiated within the callback.
 *
 * @param store - The store containing the theme promise
 * @param callback - The function to execute within the context
 */
declare function runWithGlobalThemeContext(store: GlobalThemeContext, callback: () => void): void;
/**
 * Gets the current global theme context from AsyncLocalStorage.
 * In development mode, validates that the context is initialized.
 * In production, returns the context directly for better performance.
 *
 * @returns The current context store or undefined if not initialized
 */
declare function getContext(): GlobalThemeContext | undefined;

declare function getFonts(cdn?: string): Promise<FontsResult | undefined>;
declare function getStyles(): Promise<StyleObject | undefined>;
declare function getThemeCSS(): string | undefined;
declare function getThemeMode(): ThemeMode | undefined;

export { getContext, getFonts, getGlobalThemeContextScript, getStyles, getThemeCSS, getThemeMode, runWithGlobalThemeContext };
